// src/components/Contact.jsx
import { useState } from 'react';
import './Contact.css';

const contactInfo = [
  { 
    icon: '👨‍🏫', 
    title: 'Faculty Coordinator', 
    main: 'Prof. Siddaling: +91 9916575250', 
    sub: 'Prof. Sudha: +91 8105448143' 
  },
  { 
    icon: '👨‍🎓', 
    title: 'Student Coordinators', 
    main: 'Aditya: +91 9307698460 | Omkar: +91 9380473500', 
    main: 'Mahantesh: +91 9110471767 | Madhura: +91 9663926444' ,
    main: 'Nikita: +91 9034850991', 
    s: 'Mansi: +91 8431256750' 
  },
  { 
    icon: '👩‍🎓', 
    title: 'More Coordinators', 
    main: 'Nikita: +91 9034850991', 
    sub: 'Mansi: +91 8431256750' 
  },
  { 
    icon: '📍', 
    title: 'Venue', 
    main: 'Innovation Hub, Bengaluru', 
    sub: 'Karnataka Tech Park, Whitefield' 
  },
  { 
    icon: '💼', 
    title: 'Sponsorship', 
    main: 'sponsors@prompttoapp.com', 
    sub: 'Partnership & advertising queries' 
  },
];
export default function Contact() {
  const [form, setForm] = useState({ name: '', email: '', subject: '', message: '' });
  const [sent, setSent] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = (e) => {
    e.preventDefault();
    // In production: call your API here
    setSent(true);
    setTimeout(() => setSent(false), 4000);
    setForm({ name: '', email: '', subject: '', message: '' });
  };

  return (
    <section id="contact" className="contact-section">
      <p className="section-tag">Get In Touch</p>
      <h2 className="section-title">
        Contact <span className="gradient-text">Us</span>
      </h2>

      <div className="contact-grid">
        {/* Info column */}
        <div className="contact-info fade-in">
          <p className="contact-intro">
            Have a question about registration, sponsorship, or the competition?
            We'd love to hear from you. Reach out and we'll respond within 24 hours.
          </p>
          {contactInfo.map(({ icon, title, main, sub }) => (
            <div className="contact-item" key={title}>
              <div className="contact-icon">{icon}</div>
              <div>
                <h5>{title}</h5>
                <p>{main}</p>
                <span>{sub}</span>
              </div>
            </div>
          ))}
        </div>

        {/* Form column */}
        <form className="contact-form card fade-in" onSubmit={handleSubmit}>
          <div>
            <p className="form-title">Send us a message</p>
            <p className="form-subtitle">We'll respond within one business day</p>
          </div>

          <div className="form-group">
            <label>Full Name</label>
            <input type="text" name="name" placeholder="Arjun Sharma" value={form.name} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label>Email Address</label>
            <input type="email" name="email" placeholder="arjun@college.edu" value={form.email} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label>Subject</label>
            <input type="text" name="subject" placeholder="Team registration query" value={form.subject} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label>Message</label>
            <textarea name="message" placeholder="Hi, I'd like to know more about..." value={form.message} onChange={handleChange} required />
          </div>

          <button type="submit" className="form-submit btn-primary">
            {sent ? '✅ Message Sent!' : 'Send Message →'}
          </button>
        </form>
      </div>
    </section>
  );
}
